parameters.jsCode:
// Summarize data quality results
const data = $input.first().json.data;

const summary = {
  processed_at: new Date().toISOString(),
  total_issues: data.total_issues || 0,
  auto_fixed: data.auto_fixed || 0,
  requires_review: data.requires_review || 0,
  by_type: data.by_type || {},
  archived_leads: data.archived_leads || 0,
  closed_quotes: data.closed_quotes || 0
};

console.log('Data Quality Summary:', JSON.stringify(summary));

return {
  ...summary,
  should_notify: summary.requires_review > 10
};

